// // This module decrements a 4-bit binary counter on the rising edge of the clock. If the reset signal is high, the counter is reset to 7.
module binary_counter(clk, reset, count);

    input clk;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge clk)
        begin
            if (reset)
                count <= 0;
            else
                count <= count + 1;
        end

endmodule
